import {
  html,
  customElement,
  property,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import type { UmbPropertyEditorUiElement } from "@umbraco-cms/backoffice/property-editor";
import { UmbLitElement } from "@umbraco-cms/backoffice/lit-element";
import { UmbPropertyEditorConfigCollection } from "@umbraco-cms/backoffice/property-editor";
import { UmbSubmittableWorkspaceContext } from "@umbraco-cms/backoffice/workspace";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../section/forms/workspace/form-workspace.context-token";
import { FORMS_DATASOURCE_WORKSPACE_CONTEXT } from "../../section/datasources/workspace/datasource-workspace.context-token";
import { FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT } from "../../section/prevaluesources/workspace/prevaluesource-workspace.context-token";
import { tryExecuteAndNotify } from "@umbraco-cms/backoffice/resources";
import { PickerItem, PickerService } from "@umbraco-forms/generated";
import { UUISelectEvent } from "@umbraco-cms/backoffice/external/uui";

const elementName = "forms-document-type-field-picker-property-editor";

@customElement(elementName)
export class FormsDocumentTypeFieldPickerPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  @property()
  value = "";

  @state()
  private _settingProvidingDocTypeAlias: string = "";

  @state()
  private _properties: Array<PickerItem> = [];

  public set config(config: UmbPropertyEditorConfigCollection | undefined) {
    this._settingProvidingDocTypeAlias = config?.getValueByAlias('settingProvidingDocTypeAlias') || "";
  }

  constructor() {
    super();

    this.#observeSettingsFromContext();
	}

  #observeSettingsFromContext() {

    // This property editor is used in settings, which could be part of a field, workflow, data source or prevalue source.
    // As such we'll be in one of the forms, data source or prevalue source contexts, but we don't know which.
    // So just try them all, one will succeed and we'll be able to access the settings from that.
    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (context) => {
      if (!context) return;
			this.#observeSettings(context);
		});
    this.consumeContext(FORMS_DATASOURCE_WORKSPACE_CONTEXT, (context) => {
      if (!context) return;
			this.#observeSettings(context);
		})
    this.consumeContext(FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT, (context) => {
      if (!context) return;
			this.#observeSettings(context);
		})
  }

	#observeSettings(context: UmbSubmittableWorkspaceContext) {
		this.observe(context["data"], async (data) => {
      if (this._settingProvidingDocTypeAlias.length === 0) return;
      const settingValue = data?.settings[this._settingProvidingDocTypeAlias];
      if (settingValue) {
        await this.#populatePropertyTypeAliases(settingValue)
      }
    });
	}

  async #populatePropertyTypeAliases(docTypeAlias: string) {
		const { data } = await tryExecuteAndNotify(
			this,
			PickerService.getPickerDocumentTypeByAliasProperties({ alias: docTypeAlias })
		);
    if (data) {
      this._properties = data;
    }
  }

  #onChange(e: UUISelectEvent) {
    const newValue = e.target.value.toString();
    if (newValue === this.value) return;
    this.value = newValue;
    this.dispatchEvent(new CustomEvent("property-value-change"));
  }

  render() {
    return html`
      <uui-select
        id="field"
        @change=${this.#onChange}
        .options=${[
          ...["Id", "Key", "Name"]
            .map((p) => ({
              name: p,
              value: p,
              group: this.localize.term("formPropertyEditors_standardFields"),
              selected: this.value === p || (!this.value && p === "Name")
            })),
          ...this._properties
            .map((p) => ({
              name: p.value,
              value: p.id,
              group: this.localize.term("formPropertyEditors_customFields"),
              selected: this.value === p.id
            })),
        ]}
      >
      </uui-select>
    `;
  }
}

export default FormsDocumentTypeFieldPickerPropertyUiElement;

declare global {
	interface HTMLElementTagNameMap {
		[elementName]: FormsDocumentTypeFieldPickerPropertyUiElement;
	}
}

